{
  "module": "01-layout.md",
  "group": "01 — Layout Components & Basic UI Elements",
  "apiCount": 23,
  "apis": [
    {
      "name": "Column",
      "purpose": "沿垂直方向布局的容器组件，可设置子组件间距",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "沿水平方向布局的容器组件，可设置子组件间距",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序依次入栈，后一个覆盖前一个",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Flex",
      "purpose": "弹性方式布局子组件的容器组件，可高效排列、对齐子元素并分配剩余空间",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Text",
      "purpose": "显示一段文本的组件，支持Span和ImageSpan子组件实现图文混排",
      "anchor": "text",
      "status": "found"
    },
    {
      "name": "Button",
      "purpose": "按钮组件，可快速创建不同样式的按钮（Normal/Capsule/Circle/RoundedRectangle）",
      "anchor": "button",
      "status": "found"
    },
    {
      "name": "Image",
      "purpose": "图片组件，支持png/jpg/svg/webp/gif/tiff格式，支持本地/网络/Base64图片源",
      "anchor": "image",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，在容器主轴方向自动填充空余部分，仅父组件为Row/Column/Flex时生效",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分割不同内容块/内容元素，支持水平和垂直方向",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动的容器组件，当子组件布局尺寸超过父组件尺寸时内容可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": ".width()",
      "purpose": "设置组件自身的宽度，缺省时使用元素自身内容需要的宽度",
      "anchor": "width",
      "status": "found"
    },
    {
      "name": ".height()",
      "purpose": "设置组件自身的高度，缺省时使用元素自身内容需要的高度",
      "anchor": "height",
      "status": "found"
    },
    {
      "name": ".padding()",
      "purpose": "设置组件的内边距属性，支持Padding对象或统一Length",
      "anchor": "padding",
      "status": "found"
    },
    {
      "name": ".margin()",
      "purpose": "设置组件的外边距属性，外边距视为组件大小的一部分影响位置",
      "anchor": "margin",
      "status": "found"
    },
    {
      "name": ".backgroundColor()",
      "purpose": "设置组件背景颜色",
      "anchor": "backgroundcolor",
      "status": "found"
    },
    {
      "name": ".borderRadius()",
      "purpose": "设置边框的圆角半径，支持百分比（依据组件宽度）",
      "anchor": "borderradius",
      "status": "found"
    },
    {
      "name": ".fontSize()",
      "purpose": "设置字体大小，number类型使用fp单位",
      "anchor": "fontsize",
      "status": "found"
    },
    {
      "name": ".fontWeight()",
      "purpose": "设置文本的字体粗细，number类型取值[100,900]，取值越大越粗",
      "anchor": "fontweight",
      "status": "found"
    },
    {
      "name": ".textAlign()",
      "purpose": "设置文本段落在水平方向的对齐方式",
      "anchor": "textalign",
      "status": "found"
    },
    {
      "name": ".id()",
      "purpose": "设置组件的唯一标识，在整个应用内唯一，支持UI自动化测试",
      "anchor": "id",
      "status": "found"
    },
    {
      "name": ".alignItems()",
      "purpose": "Column中设置子组件水平对齐，Row中设置子组件垂直对齐",
      "anchor": "alignitems",
      "status": "found"
    },
    {
      "name": ".justifyContent()",
      "purpose": "Column中设置子组件垂直对齐，Row中设置子组件水平对齐",
      "anchor": "justifycontent",
      "status": "found"
    },
    {
      "name": ".onClick()",
      "purpose": "组件被点击时触发的事件回调，返回ClickEvent包含坐标等信息",
      "anchor": "onclick",
      "status": "found"
    }
  ],
  "notableFindings": [
    ".space() 在Column和Row中仅作为构造参数传入（Column({ space: 5 })），并非链式方法，无单独的.space()属性接口",
    "Flex的space参数需导入LengthMetrics（import {LengthMetrics} from '@kit.ArkUI'），支持主轴和交叉轴分别设置",
    "Column、Row、Flex的justifyContent属性从API 8开始支持",
    "Flex组件渲染时存在二次布局过程，对性能要求严格时应改用Column/Row替代",
    "Image组件使用网络图片时需要申请ohos.permission.INTERNET权限"
  ],
  "missingApis": []
}

{
  "module": "02-animation.md",
  "group": "02 — 3D Flip Animation & Transitions",
  "apiCount": 13,
  "apis": [
    {
      "name": "rotate()",
      "purpose": "组件绕指定轴旋转，支持3D旋转轴向量和perspective视距",
      "anchor": "rotate",
      "status": "found"
    },
    {
      "name": "rotate3d()",
      "purpose": "3D旋转（无独立API；通过rotate()的(x,y,z)向量实现）",
      "anchor": "rotate",
      "status": "missing"
    },
    {
      "name": "perspective()",
      "purpose": "设置3D视距（无独立API；perspective为RotateOptions的属性字段）",
      "anchor": "rotateoptions对象说明",
      "status": "missing"
    },
    {
      "name": ".animation()",
      "purpose": "组件属性变化时自动产生渐变过渡动画",
      "anchor": "animation",
      "status": "found"
    },
    {
      "name": "animateTo()",
      "purpose": "全局显式动画接口，闭包内状态变更自动产生过渡动效",
      "anchor": "animateto",
      "status": "found"
    },
    {
      "name": "transition()",
      "purpose": "组件插入/删除时配置转场过渡动画效果",
      "anchor": "transition",
      "status": "found"
    },
    {
      "name": "Animation",
      "purpose": "动画类（HarmonyOS中无独立Animation类；使用animation/animateTo接口）",
      "anchor": "属性动画-animation",
      "status": "missing"
    },
    {
      "name": "AnimationOptions",
      "purpose": "动画参数配置（HarmonyOS中使用AnimateParam对象替代）",
      "anchor": "animateparam对象说明",
      "status": "missing"
    },
    {
      "name": ".onClick() gesture",
      "purpose": "组件点击事件回调，支持触发动画",
      "anchor": "onclick",
      "status": "found"
    },
    {
      "name": "Curve",
      "purpose": "内置动画插值曲线枚举，包含Linear/Ease/EaseInOut/Friction等13种",
      "anchor": "curve",
      "status": "found"
    },
    {
      "name": "ease",
      "purpose": "Curve.Ease预定义贝塞尔曲线，动画开始和结束时速度较慢",
      "anchor": "curve",
      "status": "found"
    },
    {
      "name": "easeInOut",
      "purpose": "Curve.EaseInOut预定义贝塞尔曲线，动画先加速后减速",
      "anchor": "curve",
      "status": "found"
    },
    {
      "name": "springCurve",
      "purpose": "构造弹簧曲线对象，通过velocity/mass/stiffness/damping参数控制弹性动画",
      "anchor": "curvesspringcurve9",
      "status": "found"
    },
    {
      "name": ".opacity()",
      "purpose": "设置组件不透明度，支持动画渐变",
      "anchor": "opacity",
      "status": "found"
    },
    {
      "name": ".scale()",
      "purpose": "设置组件X/Y/Z轴缩放倍数及缩放中心点",
      "anchor": "scale",
      "status": "found"
    },
    {
      "name": ".translate()",
      "purpose": "设置组件X/Y/Z轴平移距离，z轴移动产生近大远小效果",
      "anchor": "translate",
      "status": "found"
    }
  ],
  "notableFindings": [
    "rotate3d()和perspective()无独立API；rotate()通过(x,y,z)向量实现3D旋转，perspective为RotateOptions的属性字段",
    "Animation类和AnimationOptions非独立类型；HarmonyOS统一使用AnimateParam对象配置动画参数",
    ".animation()可动画属性必须写在调用之前；animateTo()支持闭包内批量状态变更且建议通过getUIContext()调用",
    "transition()推荐使用TransitionEffect（API 10+），已取代废弃的TransitionOptions",
    "springCurve的duration受animation/animateTo控制；springMotion/responsiveSpringMotion为物理曲线不受duration控制"
  ],
  "missingApis": [
    "rotate3d()",
    "perspective()",
    "Animation",
    "AnimationOptions"
  ]
}

